function openLock(deadends, target) {
    const dead = new Set(deadends);
    const visited = new Set();
    const wheelStates = [["0000", 0]];

    if (dead.has("0000")) return -1;

    while (wheelStates.length > 0) {
        const [currentState, turns] = wheelStates.shift();

        if (currentState === target) return turns;

        for (let i = 0; i < 4; ++i) {
            const upState = currentState.slice(0, i) + ((parseInt(currentState[i]) + 1) % 10).toString() + currentState.slice(i + 1);
            const downState = currentState.slice(0, i) + ((parseInt(currentState[i]) - 1 + 10) % 10).toString() + currentState.slice(i + 1);

            if (!visited.has(upState) && !dead.has(upState)) {
                wheelStates.push([upState, turns + 1]);
                visited.add(upState);
            }

            if (!visited.has(downState) && !dead.has(downState)) {
                wheelStates.push([downState, turns + 1]);
                visited.add(downState);
            }
        }
    }
    return -1;
}
```

    The algorithm is based on a breadth-first search. We create sets for deadends and visited states, and a queue of wheel states with the number of turns for each state. If the starting state "0000" is in deadends, we return -1, as there is no solution. 

We iterate while wheelStates is not empty. On each iteration, we check if the current state is equal to the target state, and return the number of turns if they are equal. Then, for each wheel of the state, we calculate the up state and down state by adding 1 or subtracting 1 from its position respectively (modulo 10). After that, if up_state or down_state are not visited and not in deadends, we add them to wheelStates with turns + 1. Finally, we add up_state and down_state in visited states.

If there is no solution, return -1 when the wheelStates queue becomes empty.

